data class Task(
    val id: Int,
    val title: String,
    val description: String,
    val priority: String, // Low, Medium, High
    val isCompleted: Boolean = false
)

data class TaskManager(
    private val tasks: MutableList<Task> = mutableListOf()
) {
    private var nextId = 1

    // Add task
    fun addTask(title: String, description: String, priority: String): Task {
        val task = Task(nextId++, title, description, priority)
        tasks.add(task)
        return task
    }

    // Get all tasks
    fun getAllTasks(): List<Task> = tasks.toList()

    // Get task by id (nullable)
    fun getTaskById(id: Int): Task? = tasks.find { it.id == id }

    // Get tasks by priority
    fun getTasksByPriority(priority: String): List<Task> =
        tasks.filter { it.priority.equals(priority, ignoreCase = true) }

    // Mark task as completed
    fun markComplete(id: Int): Task? {
        val task = tasks.find { it.id == id }
        return task?.copy(isCompleted = true)?.also { 
            tasks[tasks.indexOf(task)] = it 
        }
    }

    // Delete task
    fun deleteTask(id: Int): Boolean {
        return tasks.removeIf { it.id == id }
    }

    // Get completed tasks
    fun getCompletedTasks(): List<Task> = tasks.filter { it.isCompleted }

    // Get pending tasks
    fun getPendingTasks(): List<Task> = tasks.filter { !it.isCompleted }

    // Sort tasks by priority
    fun sortByPriority(): List<Task> = tasks.sortedByDescending { it.priority }

    // Summary
    fun getSummary(): String {
        val total = tasks.size
        val completed = getCompletedTasks().size
        val pending = getPendingTasks().size
        val highPriority = tasks.count { it.priority == "High" && !it.isCompleted }
        return """
            Summary:
            - Total tasks: $total
            - Completed: $completed
            - Pending: $pending
            - High priority pending: $highPriority
        """.trimIndent()
    }
}

