data class Task(
    val id: Int,
    val title: String,
    val priority: String,
    val isCompleted: Boolean = false
)

class TaskManager {
    private val tasks = mutableListOf<Task>()
    private var nextId = 1

    fun addTask(title: String, priority: String): Task {
        val task = Task(nextId++, title, priority)
        tasks.add(task)
        return task
    }

    fun getAllTasks(): List<Task> = tasks.toList()

    fun getTasksByPriority(priority: String): List<Task> =
        tasks.filter { it.priority == priority }

    fun completeTask(id: Int): Task? {
        val task = tasks.find { it.id == id }
        return task?.copy(isCompleted = true)?.also {
            tasks[tasks.indexOf(task)] = it
        }
    }

    fun deleteTask(id: Int): Boolean = tasks.removeIf { it.id == id }

    fun getSummary(): String {
        val total = tasks.size
        val completed = tasks.count { it.isCompleted }
        val pending = tasks.count { !it.isCompleted }
        return "Total: $total, Completed: $completed, Pending: $pending"
    }
}

fun main() {
    val manager = TaskManager()

    manager.addTask("Learn Kotlin", "High")
    manager.addTask("Build app", "Medium")
    manager.addTask("Write tests", "Low")

    println("All: ${manager.getAllTasks()}")
    println("High: ${manager.getTasksByPriority("High")}")
    manager.completeTask(1)
    println("After complete: ${manager.getAllTasks()}")
    println(manager.getSummary())
    manager.deleteTask(2)
    println("After delete: ${manager.getAllTasks()}")
}
